import { useEffect, useState } from "react";
import API from "../api";
import Seat from "../components/seat";

export default function Reservation() {
	const [seats, setSeats] = useState([]);
	const [selected, setSelected] = useState(null);
	const [form, setForm] = useState({
		firstName: "",
		lastName: "",
		email: "",
	});

	const fetchSeats = async () => {
		const open = await API.get("/tickets/open/all");
		const closed = await API.get("/tickets/closed/all");
		setSeats(
			[...open.data, ...closed.data].sort(
				(a, b) => a.seatNumber - b.seatNumber,
			),
		);
	};

	useEffect(() => {
		fetchSeats();
	}, []);

	const bookSeat = async () => {
		await API.post(`/tickets/book/${selected.seatNumber}`, {
			name: form.firstName + " " + form.lastName,
			email: form.email,
		});

		alert("Booked Successfully");
		setSelected(null);
		fetchSeats();
	};

	return (
		<div>
			<h2>Bus Reservation</h2>

			<div
				style={{
					display: "grid",
					gridTemplateColumns: "repeat(5, 60px)",
					justifyContent: "center",
				}}>
				{seats.map((seat) => (
					<Seat key={seat.seatNumber} seat={seat} onClick={setSelected} />
				))}
			</div>

			{selected && (
				<div style={{ marginTop: 20 }}>
					<h3>Booking Seat {selected.seatNumber}</h3>

					<input
						placeholder="First Name"
						onChange={(e) => setForm({ ...form, firstName: e.target.value })}
					/>

					<input
						placeholder="Last Name"
						onChange={(e) => setForm({ ...form, lastName: e.target.value })}
					/>

					<input
						placeholder="Email"
						onChange={(e) => setForm({ ...form, email: e.target.value })}
					/>

					<button onClick={bookSeat}>Confirm Booking</button>
				</div>
			)}
		</div>
	);
}
